-- Signature skill catalog: families, discovery, action progress, hidden skills, and ultimates.

CREATE TABLE skill_families (
  id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
  family_key VARCHAR(80) NOT NULL UNIQUE,
  name VARCHAR(120) NOT NULL,
  symbol VARCHAR(20) NOT NULL DEFAULT '',
  description TEXT NOT NULL,
  identity_theme VARCHAR(255) NOT NULL,
  progression_rules_json JSON NOT NULL
);

ALTER TABLE skills
  ADD COLUMN family_id BIGINT UNSIGNED NULL AFTER skill_key,
  ADD COLUMN category VARCHAR(80) NOT NULL DEFAULT 'General' AFTER skill_type,
  ADD COLUMN rarity ENUM('common', 'uncommon', 'rare', 'epic', 'legendary', 'mythic') NOT NULL DEFAULT 'common' AFTER category,
  ADD COLUMN visibility ENUM('normal', 'secret', 'hidden') NOT NULL DEFAULT 'normal' AFTER rarity,
  ADD COLUMN family_tier INT NOT NULL DEFAULT 1 AFTER visibility,
  ADD COLUMN identity_text TEXT NULL AFTER description,
  ADD COLUMN unlock_hint TEXT NULL AFTER identity_text,
  ADD COLUMN discovery_rules_json JSON NULL AFTER requirements_json,
  ADD COLUMN evolution_rules_json JSON NULL AFTER discovery_rules_json,
  ADD CONSTRAINT fk_skills_family FOREIGN KEY (family_id) REFERENCES skill_families(id) ON DELETE SET NULL;

ALTER TABLE character_skills
  ADD COLUMN discovered_at TIMESTAMP NULL AFTER unlocked,
  ADD COLUMN discovery_context_json JSON NULL AFTER discovered_at;

CREATE TABLE skill_progress_events (
  id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
  character_life_id BIGINT UNSIGNED NOT NULL,
  skill_id BIGINT UNSIGNED NOT NULL,
  story_cycle_id BIGINT UNSIGNED NOT NULL,
  action_text TEXT NOT NULL,
  action_signature VARCHAR(160) NOT NULL,
  success_level ENUM('failed', 'partial', 'success', 'exceptional') NOT NULL,
  progress_amount INT NOT NULL DEFAULT 0,
  evidence_json JSON NOT NULL,
  created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  INDEX idx_skill_progress_character_skill (character_life_id, skill_id, created_at),
  CONSTRAINT fk_skill_progress_life FOREIGN KEY (character_life_id) REFERENCES character_lives(id) ON DELETE CASCADE,
  CONSTRAINT fk_skill_progress_skill FOREIGN KEY (skill_id) REFERENCES skills(id) ON DELETE CASCADE,
  CONSTRAINT fk_skill_progress_cycle FOREIGN KEY (story_cycle_id) REFERENCES story_cycles(id) ON DELETE CASCADE
);




-- Hidden skills never appear in normal catalogs or ordinary unlock previews.

-- Ultimate skills are mythical family conclusions or world-level authorities.
